// reference: the substructure from the misconception file's frontmatter
// refs: query result (all edges for documents with frontmatter.type == "ref")
function LiteratureReference({reference, refs, zoteroItems}) {
  const refEdge = refs.edges.find(edge => edge.node.slug === "references/"+reference.citationKey);
  const refNode = refEdge ? refEdge.node : undefined;
  const zoteroItem = zoteroItems ? zoteroItems.nodes.find(node => node.citationKey === reference.citationKey) : undefined;
  const header = zoteroItem
    ? zoteroItem.data 
      ? zoteroItem.data.creatorSummary + " " + zoteroItem.data.parsedDate.substring(0, 4)
      : reference.citationKey
    : reference.citationKey;
  return (
    <List.Item
      as={Link}
      to={`/reference/${reference.citationKey}`}
      // href={`https://www.zotero.org/groups/2535417/progmiscon/items/${zoteroReferences[reference.citationKey]}`}
      key={`zotero-${reference.citationKey}`}
    >
      <List.Icon className="file alternate outline" size='large' verticalAlign='top' />
      <List.Content>
        <List.Header>
          {/* color this like a link, without producing a nested a element */}
          <span style={{ fontSize: '110%', color: "#4183c4", wordBreak: "break-all" }}>{header}</span>
        </List.Header>
        {
          refNode ?
            <>
              <br></br><em>{refNode.frontmatter.method}</em><br/>
              <br/>{refNode.frontmatter.subjects}<br/><br/>

              {
                refNode.frontmatter.langs.map(lang => (
                  <Label
                    key={lang}
                    color="red"
                  >
                  { lang }
                  </Label>
                ))
              }
              {
                refNode.frontmatter.artifact ? <span style={{ marginLeft: "1rem" }} data-tooltip="Artifact supporting the paper is available" ><Icon className="brown archive" />Artifact</span> : null
              }
              <PhenomenonKinds phenomenonKinds={refNode.frontmatter.phenomenonKinds} phenomenaToShow={reference.phenomena} />
            </> : null
        }
      </List.Content>
    </List.Item>
  );
}

// render the kinds of phenomena, and for each kind, all the phenomena
function PhenomenonKinds({phenomenonKinds, phenomenaToShow}) {
  return (
    <div>
    {
      phenomenonKinds ? phenomenonKinds.map(kind => (
        <div key={kind.name}>
          <br/><strong data-tooltip={kind.description}>{kind.name}</strong> studied:
          <List>
          {
            kind.phenomena ? kind.phenomena.map(phenomenon => (
              phenomenaToShow && phenomenaToShow.includes(phenomenon.id)
                ? <Phenomenon key={phenomenon.id} p={phenomenon}/>
                : null
            )) : null
          }
          </List>
        </div>
      )) : null
    }
    </div>
  );
}

function Phenomenon({p}) {
  return (
    <List.Item>
      <List.Content>
        <strong>{p.id}</strong>: {p.name}
        {p.observations ? p.observations.map(o => (<Observation key={o.measure} o={o} />)) : null}
      </List.Content>
    </List.Item>
  );
}

function Observation({o}) {
  if (!o) {
    return "<p>INTERNAL ERROR! List of observations contains undefined element.</p>";
  }
  if (o.kind === "CountOf") {
    // return (
    //   <Progress
    //     key={o.measure}
    //     data-tooltip={`${o.count} of ${o.maxCount} ${o.measure} (${Math.round(o.count / o.maxCount * 1000) / 10}%)`}
    //     value={o.count}
    //     total={o.maxCount}
    //     progress='ratio'
    //   >
    //     {o.measure}
    //   </Progress>
    // );
    const nbsp = '\u00A0';
    return (
      <div style={{ marginBottom: '1em' }}>
        <div className='count-area' style={{ backgroundColor: 'rgba(0, 0, 0, 0.05)', borderRadius: '4px', padding: '0px' }}>
          <div
            className='count-bar'
            data-tooltip={`${o.count} of ${o.maxCount} ${o.measure} (${Math.round(o.count / o.maxCount * 1000) / 10}%)`}
            style={{ 
              backgroundColor: 'rgba(0, 0, 0, 0.16)', 
              borderRadius: '4px', 
              paddingTop: '4px', 
              paddingBottom: '4px', 
              width: (o.count / o.maxCount * 100) + '%'
            }}
          >
            <div className='count-label'>{o.count}{nbsp}/{nbsp}{o.maxCount}</div>
          </div>
        </div>
        <div className='count-caption' style={{ fontWeight: 700, textAlign: 'center', marginTop: '.2em' }}>
          {o.measure}
        </div>
      </div>
    );
  } else if (o.kind === "Percentage") {
    const nbsp = '\u00A0';
    return (
      <div style={{ marginBottom: '1em' }}>
        <div className='percent-area' style={{ backgroundColor: 'rgba(0, 0, 0, 0.05)', borderRadius: '4px', padding: '0px' }}>
          <div
            className='percent-bar'
            data-tooltip={`${o.percent} % ${o.measure}`} 
            style={{ 
              backgroundColor: 'rgba(0, 0, 0, 0.16)', 
              borderRadius: '4px', 
              paddingTop: '4px', 
              paddingBottom: '4px', 
              width: o.percent + '%'
            }}
          >
            <div className='percent-label'>{o.percent}{nbsp}%</div>
          </div>
        </div>
        <div className='percent-caption' style={{ fontWeight: 700, textAlign: 'center', marginTop: '.2em' }}>
          {o.measure}
        </div>
      </div>
    );
  } else if (o.kind === "Likert") {
    const totalCount = o.counts.reduce((sum, current) => sum + current, 0);
    let bars = [];
    for (let i = 0; i < o.counts.length; i++) {
      const count = o.counts[i];
      const levelLabel = o.levelLabels[i];
      const nbsp = '\u00A0';
      const nbLevelLabel = levelLabel.replace(/\s/g, nbsp);
      const bar = (
        <div
          className='likert-bar' 
          key={levelLabel} 
          data-tooltip={`${count} of ${totalCount} ${levelLabel}`} 
          style={{ 
            backgroundColor: 'rgba(0, 0, 0, 0.16)', 
            borderRadius: '4px', 
            paddingTop: '4px', 
            paddingBottom: '4px', 
            width: (100 * count / totalCount) + '%'
          }}
        >
          <div className='likert-label'>{nbLevelLabel}:{nbsp}{count}</div>
        </div>
      );
      bars.push(bar);
    }
    return (
      <div style={{ marginBottom: '1em' }}>
        <div className='likert-area' style={{ backgroundColor: 'rgba(0, 0, 0, 0.05)', borderRadius: '4px', padding: '0px' }}>
          {bars}
        </div>
        <div className='likert-caption' style={{ fontWeight: 700, textAlign: 'center', marginTop: '.2em' }}>
          {o.measure}
        </div>
      </div>
    );
  } else {
    return null;
  }
}


