export const pageQuery = graphql`
  query($slug: String!) {
    mdx(fields: { slug: { eq: $slug } }) {
      body
      rawBody
      fields {
        name
        pl
        image {
          childImageSharp {
            fluid {
              ...GatsbyImageSharpFluid
              src
            }
            resize(width: 1024, height: 512, fit: COVER, cropFocus: NORTH) {
              src
              height
            }
          }
        }
        correction {
          childMdx {
            body
            rawBody
          }
        }
        origin {
          childMdx {
            body
            rawBody
          }
        }
        symptoms {
          childMdx {
            body
            rawBody
          }
        }
        value {
          childMdx {
            body
            rawBody
          }
        }
      }
      frontmatter {
        shortDescription
        shortCorrection
        status
        observed
        pytamaroActivityVersion
        videoId
        concepts
        related {
          id
          relation
        }
        inOtherPl {
          pl
          id
        }
        plVersion {
          from
          to
        }
        specificToNm
        expressibleInNms {
          id
          how
        }
        spec {
          id
          sections
        }
        references {
          citationKey
          phenomena
          id
          name
          relationship
        }
      }
    }

    specsMdx: allMdx(filter: { fileAbsolutePath: { glob: "**/src/data/specs/*.md" } }) {
      nodes {
        parent {
          ... on File {
            name
          }
        }
        frontmatter {
          pl
          sections {
            section
            title
            url
          }
        }
      }
    }

    concepts: allFile(filter: {absolutePath: {glob: "**/src/data/concepts/*.md"}}
    ) {
      nodes {
        name
      }
    }

    zoteroItems: allZoteroItems {
      nodes {
        key
        citationKey
        data {
          parsedDate
          creatorSummary
        }
      }
    }
    
    refs: allMdx(filter: {frontmatter: {type: {eq: "ref"}}}) {
      edges {
        node {
          id
          slug
          frontmatter {
            langs
            method
            subjects
            artifact
            phenomenonKinds {
              name
              description
              phenomena {
                id
                name
                observations {
                  kind
                  measure
                  count
                  maxCount
                  percent
                  counts
                  levelLabels
                }
              }
            }
          }
          fields {
            slug
            name
            pl
          }
        }
      }
    }
  }
`
